export default function sortNumbers(arr, ascending = true) {
  // Clone to avoid mutating the original
  const copy = [...arr];

  copy.sort((a, b) => {
    if (ascending) {
      return a - b; // negative if a < b, positive if a > b
    }
    return b - a;   // flipped for descending
  });

  return copy;
}

